import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink, ActivatedRoute, Router } from '@angular/router';
import { FormsModule } from '@angular/forms';
import { SeedService } from '../../data/seed.service';

interface UserRow {
  name: string;
  email: string;
  role: string;
  status: 'active' | 'invited' | 'disabled';
}

interface Tier {
  band: string;
  threshold: string;
  rate: string;
}

interface RoleDef {
  key: string;
  label: string;
  canSee: string[];
  cannotSee: string[];
}

@Component({
  selector: 'app-settings',
  standalone: true,
  imports: [CommonModule, RouterLink, FormsModule],
  templateUrl: './settings.component.html',
  styleUrl: './settings.component.css',
})
export class SettingsComponent {
  readonly tabs = ['users', 'commission', 'roles'];
  activeTab = signal('users');

  // Editable-looking commission form state.
  defaultRate = signal('3.5');
  splitEnabled = signal(true);
  defaultSplit = signal('30');

  readonly users: UserRow[] = [
    { name: 'You (Territory Manager)', email: 'you@nexuspower.com', role: 'admin', status: 'active' },
    { name: 'Alicia Reyes', email: 'a.reyes@nexuspower.com', role: 'sales', status: 'active' },
    { name: 'Dev Patel', email: 'd.patel@nexuspower.com', role: 'sales-support', status: 'active' },
    { name: 'Morgan Lee', email: 'm.lee@nexuspower.com', role: 'sales', status: 'invited' },
    { name: 'QES Portal (Facemyer)', email: 's.facemyer@qes.com', role: 'customer', status: 'active' },
  ];

  readonly tiers: Tier[] = [
    { band: 'Tier 1', threshold: 'Up to $1M booked', rate: '3.0%' },
    { band: 'Tier 2', threshold: '$1M – $5M booked', rate: '3.5%' },
    { band: 'Tier 3', threshold: '$5M – $15M booked', rate: '4.0%' },
    { band: 'Tier 4', threshold: 'Over $15M booked', rate: '4.5%' },
  ];

  readonly roles: RoleDef[] = [
    {
      key: 'admin', label: 'Admin',
      canSee: ['All accounts & contacts', 'Margins & pricing', 'Commissions & splits', 'User & role management', 'Reports & QBRs'],
      cannotSee: [],
    },
    {
      key: 'sales', label: 'Sales',
      canSee: ['Own accounts & pipeline', 'Margins & pricing', 'Own commissions', 'Quotes, orders, forecasts'],
      cannotSee: ["Other reps' commissions", 'User & role management'],
    },
    {
      key: 'sales-support', label: 'Sales support',
      canSee: ['Accounts & contacts', 'Quotes & orders (operational)', 'Documents & tasks'],
      cannotSee: ['Margins', 'Pricing detail', 'Commissions'],
    },
    {
      key: 'customer', label: 'Customer (portal)',
      canSee: ['Own orders & ship dates', 'Own documents', 'Own pricing requests'],
      cannotSee: ['Margins', 'Internal pricing', 'Commissions', 'Other accounts'],
    },
  ];

  statusBadge(status: UserRow['status']): string {
    switch (status) {
      case 'active': return 'badge-success';
      case 'invited': return 'badge-warning';
      case 'disabled': return 'badge-neutral';
      default: return 'badge-neutral';
    }
  }

  roleBadge(role: string): string {
    switch (role) {
      case 'admin': return 'badge-info';
      case 'sales': return 'badge-success';
      case 'sales-support': return 'badge-warning';
      case 'customer': return 'badge-neutral';
      default: return 'badge-neutral';
    }
  }

  setTab(tab: string): void {
    this.router.navigate([], { queryParams: { tab }, queryParamsHandling: 'merge' });
  }

  noop(): void { /* mockup no-op */ }

  constructor(public seed: SeedService, private route: ActivatedRoute, private router: Router) {
    this.route.queryParamMap.subscribe((q) => {
      const t = q.get('tab');
      this.activeTab.set(t && this.tabs.includes(t) ? t : 'users');
    });
  }
}
